const BIRTH_NEIGHBOR_COUNT = 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const survivors = cells.filter(([x, y]) => survives(countLiveNeighbors(x, y, liveSet)));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const key = cellKey(nx, ny);
      if (!liveSet.has(key)) candidates.set(key, [nx, ny]);
    }
  }
  const births: Cell[] = [];
  for (const [, cell] of candidates) {
    if (countLiveNeighbors(cell[0], cell[1], liveSet) === BIRTH_NEIGHBOR_COUNT) {
      births.push(cell);
    }
  }
  return [...survivors, ...births];
}

