const BIRTH_NEIGHBOR_COUNT = 3;

function deadNeighborsOf(cells: Cell[], liveSet: Set<string>): Map<string, Cell> {
  const deadNeighbors = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const [nx, ny] = [x + dx, y + dy];
      const key = cellKey(nx, ny);
      if (!liveSet.has(key)) deadNeighbors.set(key, [nx, ny]);
    }
  }
  return deadNeighbors;
}

function isBorn(cell: Cell, liveSet: Set<string>): boolean {
  return countLiveNeighbors(cell[0], cell[1], liveSet) === BIRTH_NEIGHBOR_COUNT;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const survivors = cells.filter(([x, y]) => survives(countLiveNeighbors(x, y, liveSet)));
  const births = [...deadNeighborsOf(cells, liveSet).values()].filter((cell) => isBorn(cell, liveSet));
  return [...survivors, ...births];
}
